protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // [EF9 Breaking] HasIndex throws for Cosmos entities — manage indexing
    // via Azure Portal or Bicep/Terraform indexing policy instead.

    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // [EF9 Breaking] Default discriminator property renamed from
        // "Discriminator" to "$type". Preserve old name so existing 500K
        // documents and direct SQL queries (c.Discriminator) keep working.
        entity.HasDiscriminator<string>("Discriminator");

        // [EF9 Breaking] id values no longer include the discriminator
        // (EF8 wrote "Product|123", EF9 writes "123"). Preserve compound
        // format so FindAsync/point-reads resolve existing documents.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

